214:         // Fallback: old JSON format
215:         val jsonMatch = Regex("""\{[^}]+\}""").find(response) ?: return null
216:         return try {
217:             val json = jsonMatch.value
218:             val name = Regex(""""tool_name"\s*:\s*"(\w+)"""").find(json)?.groupValues?.get(1)
219:             val args = Regex(""""arguments"\s*:\s*(\{[^}]+\})""").find(json)?.groupValues?.get(1)
220:             if (name != null && args != null) Pair(name, args) else null
221:         } catch (e: Exception) {
